import{_ as a,o as t,c as s,a3 as o}from"./chunks/framework.DXXx-gl1.js";const c=JSON.parse('{"title":"Debugging Skills","description":"","frontmatter":{},"headers":[],"relativePath":"PortingGuides/Debug.md","filePath":"PortingGuides/Debug.md","lastUpdated":1771002312000}'),r={name:"PortingGuides/Debug.md"};function i(n,e,l,u,p,d){return t(),s("div",null,[...e[0]||(e[0]=[o(`<h1 id="debugging-skills" tabindex="-1">Debugging Skills <a class="header-anchor" href="#debugging-skills" aria-label="Permalink to &quot;Debugging Skills&quot;">​</a></h1><h2 id="enable-log-output" tabindex="-1">Enable log output <a class="header-anchor" href="#enable-log-output" aria-label="Permalink to &quot;Enable log output&quot;">​</a></h2><p>Our UEFI provides 4 ways currently for getting UEFI logs.</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>  USE_SCREEN_FOR_SERIAL_OUTPUT    = 0</span></span>
<span class="line"><span>  USE_UART_GENI_FOR_SERIAL_OUTPUT = 0</span></span>
<span class="line"><span>  USE_UART_DM_FOR_SERIAL_OUTPUT   = 0</span></span>
<span class="line"><span>  USE_MEMORY_FOR_SERIAL_OUTPUT    = 0</span></span></code></pre></div><p>Only one of them can be enabled at the same time.</p><h3 id="use-screen-for-serial-output" tabindex="-1">USE_SCREEN_FOR_SERIAL_OUTPUT <a class="header-anchor" href="#use-screen-for-serial-output" aria-label="Permalink to &quot;USE_SCREEN_FOR_SERIAL_OUTPUT&quot;">​</a></h3><p>Set to <strong>1</strong> to enable serial output via screen. Logs will be printed to screen directly. This way is very <strong>useful</strong> for devices without a UART.</p><h3 id="use-uart-geni-for-serial-output" tabindex="-1">USE_UART_GENI_FOR_SERIAL_OUTPUT <a class="header-anchor" href="#use-uart-geni-for-serial-output" aria-label="Permalink to &quot;USE_UART_GENI_FOR_SERIAL_OUTPUT&quot;">​</a></h3><p>Set to <strong>1</strong> to enable serial output via a real serial port. Logs will be printed to the geni uart address at <code>gAndromedaPkgTokenSpaceGuid.PcdUartSerialBase</code> which is defined in <em>Silicon/QC/XXX/QcomPkg/QcomPkg.dsc.inc</em>.</p><h3 id="use-uart-dm-for-serial-output" tabindex="-1">USE_UART_DM_FOR_SERIAL_OUTPUT <a class="header-anchor" href="#use-uart-dm-for-serial-output" aria-label="Permalink to &quot;USE_UART_DM_FOR_SERIAL_OUTPUT&quot;">​</a></h3><p>Similar to <strong>USE_UART_GENI_FOR_SERIAL_OUTPUT</strong>. It&#39;s used for older Qualcomm platforms like msm8996.</p><h3 id="use-memory-for-serial-output" tabindex="-1">USE_MEMORY_FOR_SERIAL_OUTPUT <a class="header-anchor" href="#use-memory-for-serial-output" aria-label="Permalink to &quot;USE_MEMORY_FOR_SERIAL_OUTPUT&quot;">​</a></h3><p>Set to <strong>1</strong> to print logs to pstore memory. It&#39;s useful when you have JTAG or EUD enabled on your device. The log output region is defined in your device&#39;s <em>Library/PlatformMemoryMapLib/PlatformMemoryMapLib.c</em>.<br> The region must be named <em>PStore</em> like this:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>{&quot;PStore&quot;, &lt;StartAddress&gt;, &lt;Size&gt;, AddMem, MEM_RES, SYS_MEM_CAP, Reserv, WRITE_THROUGH_XN},</span></span></code></pre></div>`,14)])])}const g=a(r,[["render",i]]);export{c as __pageData,g as default};
